import os

def delete_directory(path):
    """
    Recursively delete a directory.

    Args:
        path (str): The path to the directory to delete.
    """
    if os.path.exists(path):
        if os.path.isfile(path):
            print(f"Error: {path} is a file, not a directory.")
        else:
            response = input(f"Are you sure you want to delete {path}? (y/n): ")
            if response.lower() == 'y':
                try:
                    for item in os.listdir(path):
                        item_path = os.path.join(path, item)
                        if os.path.isdir(item_path):
                            delete_directory(item_path)
                        else:
                            os.remove(item_path)
                    os.rmdir(path)
                    print(f"{path} deleted successfully.")
                except Exception as e:
                    print(f"Error deleting {path}: {e}")
            else:
                print(f"Delete operation cancelled for {path}.")
    else:
        print(f"Error: {path} does not exist.")

# Example usage:
delete_directory('/path/to/directory')
